import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicEceba() {
        // "eceba" k=2: longest substring with <=2 distinct chars is "ece" (length 3)
        assertEquals(3, new Solution().longestKDistinct("eceba", 2));
    }

    @Test
    void allSameChar() {
        // "aa" k=1: only one distinct char, whole string qualifies
        assertEquals(2, new Solution().longestKDistinct("aa", 1));
    }

    @Test
    void emptyString() {
        // Empty input must return 0
        assertEquals(0, new Solution().longestKDistinct("", 2));
    }

    @Test
    void kZeroReturnsZero() {
        // k=0 means zero distinct chars allowed — no substring of length > 0 qualifies
        assertEquals(0, new Solution().longestKDistinct("abc", 0));
    }

    @Test
    void kLargerThanAlphabet() {
        // k >= number of distinct chars in s — whole string is the answer
        assertEquals(5, new Solution().longestKDistinct("abcde", 5));
    }

    @Test
    void kOneLongestRun() {
        // "aaabbbccc" k=1: longest run of one char is "aaa" or "bbb" or "ccc" = 3
        assertEquals(3, new Solution().longestKDistinct("aaabbbccc", 1));
    }

    @Test
    void adversarialAlternating() {
        // "ababababab" k=2: alternating a/b, entire string has 2 distinct chars
        assertEquals(10, new Solution().longestKDistinct("ababababab", 2));
    }
}
